function ToggleSwitch({
  checked,
  disabled,
  onChange
}: {
  checked: boolean;
  disabled?: boolean;
  onChange: (nextValue: boolean) => void;
}) {
  const isDisabled = Boolean(disabled);
  return (
    <button
      type="button"
      role="switch"
      aria-checked={checked}
      aria-disabled={isDisabled}
      onClick={() => {
        if (isDisabled) return;
